/* =====================================================================
   CONFIG — single source of truth. Update these and the whole site
   reflects it. No need to hunt through markup.
===================================================================== */
const CONFIG = {
  email: "piyushchaudhary526@gmail.com",
  phone: "+91 7990127718",
  resumeUrl: "./Piyxshh-Resume.pdf",
  photoUrl: "data:image/png;base64,", // embedded inline so it never 404s — replace with your own photo's base64 or a hosted URL
  socials: {
    behance: "https://www.behance.net/piyxshh",
  linkedin: "https://www.linkedin.com/in/piyxshh",
  instagram: "https://www.instagram.com/piyush_7544"
  }
};

document.addEventListener("DOMContentLoaded", () => {

  /* ---------- apply CONFIG ---------- */
  document.getElementById("emailValue").textContent = CONFIG.email;
  document.getElementById("emailRow").href = "mailto:" + CONFIG.email;
  document.getElementById("phoneValue").textContent = CONFIG.phone;
  document.getElementById("phoneRow").href = "tel:" + CONFIG.phone.replace(/\s+/g,"");
  document.getElementById("resumeBtn").href = CONFIG.resumeUrl;
  Object.entries(CONFIG.socials).forEach(([key, url]) => {
    const el = document.getElementById("s-" + key);
    if (el) el.href = url;
  });
  if (CONFIG.photoUrl){
    const photoHtml = '<img src="'+CONFIG.photoUrl+'" alt="Piyush Chaudhary logo" onerror="this.remove(); this.parentElement.textContent=\'PC\'; this.parentElement.style.background=\'\';">';
    const profileEl = document.getElementById("profilePhotoInner");
    const heroEl = document.getElementById("heroAvatarInner");
    profileEl.innerHTML = photoHtml;
    heroEl.innerHTML = photoHtml;
    profileEl.style.background = "none";
    heroEl.style.background = "none";
  }

  /* ---------- loader ---------- */
  window.addEventListener("load", () => {
    setTimeout(() => document.getElementById("loader").classList.add("hide"), 500);
  });
  setTimeout(() => document.getElementById("loader").classList.add("hide"), 2200);

  const nameEl = document.getElementById("nameLine");
  /* ── ROLLING TEXT REVEAL — slot-machine reel effect for "THE PC" ────────
     Each character spins forward through the alphabet like a physical reel,
     decelerating and snapping into place left-to-right with a stagger.
  ────────────────────────────────────────────────────────────────────────── */
  (function rollingReveal(){
    const TARGET = "THE PC";
    const REEL   = "ABCDEFGHIJKLMNOPQRSTPIYUSH0CHAUDHARY";
    // Frame each character locks into its final value (space = 0 → instant)
    const SETTLE = [32, 42, 52, 0, 62, 72];
    // Random start offsets so the reels don't all spin identically
    const starts = TARGET.split("").map(() => Math.floor(Math.random() * REEL.length));
    let   frame  = 0;

    // Apply gradient-text style directly (works with plain textContent)
    nameEl.style.display              = "block";
    nameEl.style.fontFamily           = "var(--font-display)";
    nameEl.style.fontWeight           = "700";
    nameEl.style.letterSpacing        = "-.02em";
    nameEl.style.background           = "var(--grad)";
    nameEl.style.backgroundSize       = "300% 100%";
    nameEl.style.webkitBackgroundClip = "text";
    nameEl.style.backgroundClip       = "text";
    nameEl.style.color                = "transparent";
    nameEl.style.opacity              = "0";

    setTimeout(()=>{
      nameEl.style.transition = "opacity .2s ease";
      nameEl.style.opacity    = "1";

      function tick(){
        let out  = "";
        let done = true;

        for(let i = 0; i < TARGET.length; i++){
          if(TARGET[i] === " "){ out += "\u00A0"; continue; }

          const settle = SETTLE[i];
          if(frame >= settle){
            out += TARGET[i];                          // locked — show final char
          } else {
            // Spin speed starts fast and decelerates as it nears the settle frame.
            // stepSize 8→1 gives a natural "slowing reel" feel.
            const progress = frame / settle;           // 0 → 1
            const stepSize = Math.max(1, Math.round(8 * (1 - progress)));
            const idx      = (starts[i] + frame * stepSize) % REEL.length;
            out += REEL[idx];
            done = false;
          }
        }

        nameEl.textContent = out;
        frame++;
        if(!done){ requestAnimationFrame(tick); }
        else     { nameEl.textContent = TARGET;  }
      }

      requestAnimationFrame(tick);
    }, 320);
  })();

  /* ---------- rotating role text ---------- */
  const roles = ["UI/UX Designer", "Product Design", "User Interface", "User Experience", "Wireframing"];
  let roleIndex = 0;
  const roleEl = document.getElementById("roleText");
  setInterval(() => {
    roleIndex = (roleIndex + 1) % roles.length;
    roleEl.style.opacity = 0;
    roleEl.style.transform = "translateY(6px)";
    setTimeout(() => {
      roleEl.textContent = roles[roleIndex];
      roleEl.style.transition = "opacity .4s ease, transform .4s ease";
      roleEl.style.opacity = 1;
      roleEl.style.transform = "translateY(0)";
    }, 220);
  }, 2400);

  /* ---------- bottom nav / page switching ---------- */
  const navItems = document.querySelectorAll(".nav-item");
  const indicator = document.getElementById("navIndicator");
  const pages = { home: document.getElementById("home"), about: document.getElementById("about"), contact: document.getElementById("contact") };

  function placeIndicator(btn){
    indicator.style.width = btn.offsetWidth + "px";
    indicator.style.transform = "translateX(" + (btn.offsetLeft - 6) + "px)";
  }
  placeIndicator(document.querySelector(".nav-item.active"));
  window.addEventListener("resize", () => placeIndicator(document.querySelector(".nav-item.active")));


  /* ────────────────────────────────────────────────────────────────────────
     CONTACT ICONS  (base64 embedded, white bg removed)
  ──────────────────────────────────────────────────────────────────────── */
  const CONTACT_ICONS = ["data:image/png;base64,", "data:image/png;base64,", "data:image/png;base64,", "data:image/png;base64,", "data:image/png;base64,"];

  /* ────────────────────────────────────────────────────────────────────────
     ABOUT PAGE BACKGROUND — dark workshop / design-tools style
     Inspired by: Emensta workshop background
  ──────────────────────────────────────────────────────────────────────── */
  const aboutBg = document.getElementById('about-bg');
  const actxW = aboutBg.getContext('2d');
  let aboutAnimId = null;

  function sizeAboutBg(){
    aboutBg.width  = window.innerWidth;
    aboutBg.height = window.innerHeight;
  }
  sizeAboutBg();
  window.addEventListener('resize', sizeAboutBg);

  // Element definitions — sliders, bars, rings, rects, sparkles
  function makeAboutElements(){
    const W = aboutBg.width, H = aboutBg.height;
    const elems = [];
    // Horizontal sliders
    for(let i=0;i<6;i++) elems.push({
      type:'slider', x:Math.random()*W, y:Math.random()*H,
      w:Math.random()*80+60, val:Math.random(),
      color:'rgba(180,140,60,0.55)',
      vx:(Math.random()-.5)*.22, vy:(Math.random()-.5)*.18,
    });
    // Vertical color bars
    const barColors=['#c88a20','#c82020','#d46010','#e0b830','#9c1a1a'];
    for(let i=0;i<12;i++) elems.push({
      type:'bar', x:Math.random()*W, y:Math.random()*H,
      h:Math.random()*60+20, color:barColors[i%barColors.length],
      vx:(Math.random()-.5)*.18, vy:(Math.random()-.5)*.22,
    });
    // Concentric rings
    for(let i=0;i<4;i++) elems.push({
      type:'rings', x:Math.random()*W, y:Math.random()*H,
      r:Math.random()*28+22, phase:Math.random()*Math.PI*2,
      vx:(Math.random()-.5)*.1, vy:(Math.random()-.5)*.1,
    });
    // Small rectangles
    for(let i=0;i<14;i++) elems.push({
      type:'rect', x:Math.random()*W, y:Math.random()*H,
      w:Math.random()*30+10, h:Math.random()*14+6,
      alpha:Math.random()*.4+.1,
      vx:(Math.random()-.5)*.2, vy:(Math.random()-.5)*.2,
      rot:Math.random()*Math.PI, vrot:(Math.random()-.5)*.008,
    });
    // Diagonal dashes
    for(let i=0;i<18;i++) elems.push({
      type:'dash', x:Math.random()*W, y:Math.random()*H,
      len:Math.random()*18+6, angle:Math.random()*Math.PI,
      alpha:Math.random()*.35+.1,
      vx:(Math.random()-.5)*.25, vy:(Math.random()-.5)*.25,
    });
    // Gold sparkles
    for(let i=0;i<20;i++) elems.push({
      type:'spark', x:Math.random()*W, y:Math.random()*H,
      r:Math.random()*2.4+.6, phase:Math.random()*Math.PI*2,
      vx:(Math.random()-.5)*.3, vy:(Math.random()-.5)*.3,
    });
    return elems;
  }
  let aboutElems = makeAboutElements();

  function drawAboutBg(ts){
    const W=aboutBg.width, H=aboutBg.height;
    const ctx=actxW;
    ctx.clearRect(0,0,W,H);
    // Warm dark overlay
    const grd=ctx.createLinearGradient(0,0,W,H);
    grd.addColorStop(0,'rgba(14,10,4,.82)');
    grd.addColorStop(1,'rgba(22,14,4,.78)');
    ctx.fillStyle=grd; ctx.fillRect(0,0,W,H);
    const t=ts*.001;
    for(const e of aboutElems){
      e.x+=e.vx; e.y+=e.vy;
      if(e.x<-120) e.x=W+60; if(e.x>W+120) e.x=-60;
      if(e.y<-120) e.y=H+60; if(e.y>H+120) e.y=-60;
      if(e.rot!==undefined){ e.rot+=e.vrot; }
      if(e.type==='slider'){
        const handleX=e.x+e.w*e.val;
        ctx.save();
        ctx.globalAlpha=.55;
        ctx.beginPath();
        ctx.roundRect(e.x-e.w*.5, e.y-3, e.w, 6, 3);
        ctx.fillStyle='rgba(120,100,50,.45)'; ctx.fill();
        ctx.beginPath();
        ctx.arc(handleX-e.w*.5, e.y, 7, 0, Math.PI*2);
        ctx.fillStyle=e.color; ctx.fill();
        ctx.restore();
      } else if(e.type==='bar'){
        ctx.save();
        ctx.globalAlpha=.45;
        const grad=ctx.createLinearGradient(e.x,e.y-e.h*.5,e.x,e.y+e.h*.5);
        grad.addColorStop(0,e.color+'bb'); grad.addColorStop(1,'transparent');
        ctx.fillStyle=grad;
        ctx.fillRect(e.x-2.5,e.y-e.h*.5,5,e.h);
        ctx.restore();
      } else if(e.type==='rings'){
        ctx.save();
        ctx.globalAlpha=.28+.08*Math.sin(t*1.4+e.phase);
        for(let ring=0;ring<3;ring++){
          const rr=e.r*(ring+1)*.85;
          ctx.beginPath(); ctx.arc(e.x,e.y,rr,0,Math.PI*2);
          ctx.strokeStyle='rgba(200,150,40,.6)'; ctx.lineWidth=1.2; ctx.stroke();
        }
        ctx.restore();
      } else if(e.type==='rect'){
        ctx.save();
        ctx.globalAlpha=e.alpha;
        ctx.translate(e.x,e.y); ctx.rotate(e.rot);
        ctx.fillStyle='rgba(100,90,70,.5)';
        ctx.fillRect(-e.w*.5,-e.h*.5,e.w,e.h);
        ctx.restore();
      } else if(e.type==='dash'){
        ctx.save();
        ctx.globalAlpha=e.alpha;
        ctx.translate(e.x,e.y); ctx.rotate(e.angle);
        ctx.strokeStyle='rgba(180,140,60,.6)'; ctx.lineWidth=1.2;
        ctx.beginPath(); ctx.moveTo(-e.len*.5,0); ctx.lineTo(e.len*.5,0);
        ctx.stroke(); ctx.restore();
      } else if(e.type==='spark'){
        const alpha=.5+.3*Math.sin(t*2.2+e.phase);
        ctx.save(); ctx.globalAlpha=alpha;
        ctx.fillStyle='rgba(230,190,60,.9)';
        ctx.beginPath(); ctx.arc(e.x,e.y,e.r,0,Math.PI*2); ctx.fill();
        ctx.restore();
      }
    }
    aboutAnimId=requestAnimationFrame(drawAboutBg);
  }
  function startAboutBg(){
    if(aboutAnimId) return;
    aboutBg.classList.add('visible');
    aboutAnimId=requestAnimationFrame(drawAboutBg);
  }
  function stopAboutBg(){
    if(aboutAnimId){ cancelAnimationFrame(aboutAnimId); aboutAnimId=null; }
    aboutBg.classList.remove('visible');
  }

  /* ────────────────────────────────────────────────────────────────────────
     CONTACT PAGE BACKGROUND — rich blue-purple gradient + floating icons
     Inspired by: Emensta contact page background
  ──────────────────────────────────────────────────────────────────────── */
  const contactBg = document.getElementById('contact-bg');
  const cctx = contactBg.getContext('2d');
  let contactAnimId = null;

  function sizeContactBg(){
    contactBg.width  = window.innerWidth;
    contactBg.height = window.innerHeight;
  }
  sizeContactBg();
  window.addEventListener('resize', sizeContactBg);

  // Pre-load the 5 contact icons
  /* ── CONTACT BG: floating phone + email emoji icons at 30×30 ─────────── */
  // Emoji list cycling for the contact page floating icons
  const CONTACT_EMOJI = ['📞','📩','📧','💬'];

  function makeContactElements(){
    const W=contactBg.width, H=contactBg.height;
    const elems=[];
    // Floating emoji icons at 30×30
    for(let i=0;i<22;i++) elems.push({
      type:'emoji',
      emoji: CONTACT_EMOJI[i % CONTACT_EMOJI.length],
      x: Math.random()*W, y: Math.random()*H,
      size: Math.random()*10+26, // 26-36px, center around 30px
      rot: (Math.random()-.5)*.4,
      vx: (Math.random()-.5)*.32,
      vy: (Math.random()-.5)*.26,
      vrot: (Math.random()-.5)*.006,
      alpha: Math.random()*.5+.2,
      phase: Math.random()*Math.PI*2,
    });
    // Glowing dot particles
    for(let i=0;i<35;i++) elems.push({
      type:'dot', x:Math.random()*W, y:Math.random()*H,
      r:Math.random()*2.2+.6, phase:Math.random()*Math.PI*2,
      color:['rgba(130,160,255,.55)','rgba(190,120,255,.45)','rgba(80,210,255,.45)'][i%3],
      vx:(Math.random()-.5)*.35, vy:(Math.random()-.5)*.3,
    });
    // Dashed connection lines
    for(let i=0;i<6;i++) elems.push({
      type:'line',
      x1:Math.random()*W, y1:Math.random()*H,
      x2:Math.random()*W, y2:Math.random()*H,
      vx1:(Math.random()-.5)*.22, vy1:(Math.random()-.5)*.22,
      vx2:(Math.random()-.5)*.22, vy2:(Math.random()-.5)*.22,
      alpha:Math.random()*.14+.05,
    });
    // Concentric pulse rings
    for(let i=0;i<4;i++) elems.push({
      type:'ring', x:Math.random()*W, y:Math.random()*H,
      r:Math.random()*36+18, phase:Math.random()*Math.PI*2,
      vx:(Math.random()-.5)*.1, vy:(Math.random()-.5)*.1,
    });
    return elems;
  }
  let contactElems = makeContactElements();

  function drawContactBg(ts){
    const W=contactBg.width, H=contactBg.height;
    const ctx=cctx; const t=ts*.001;
    ctx.clearRect(0,0,W,H);
    // Deep blue-purple gradient base
    const bg=ctx.createRadialGradient(W*.42,H*.28,40,W*.5,H*.5,Math.max(W,H)*.95);
    bg.addColorStop(0,'rgba(12,18,64,.92)');
    bg.addColorStop(.4,'rgba(20,8,52,.90)');
    bg.addColorStop(1,'rgba(4,5,30,.95)');
    ctx.fillStyle=bg; ctx.fillRect(0,0,W,H);
    // Blue glow blob — top right
    const b1=ctx.createRadialGradient(W*.78,H*.12,0,W*.78,H*.12,W*.38);
    b1.addColorStop(0,'rgba(55,100,235,.14)'); b1.addColorStop(1,'transparent');
    ctx.fillStyle=b1; ctx.fillRect(0,0,W,H);
    // Purple glow blob — bottom left
    const b2=ctx.createRadialGradient(W*.12,H*.82,0,W*.12,H*.82,W*.32);
    b2.addColorStop(0,'rgba(145,55,235,.11)'); b2.addColorStop(1,'transparent');
    ctx.fillStyle=b2; ctx.fillRect(0,0,W,H);
    // Cyan accent blob — center-right
    const b3=ctx.createRadialGradient(W*.85,H*.55,0,W*.85,H*.55,W*.22);
    b3.addColorStop(0,'rgba(30,200,220,.07)'); b3.addColorStop(1,'transparent');
    ctx.fillStyle=b3; ctx.fillRect(0,0,W,H);
    // Subtle overall darkening veil
    ctx.fillStyle='rgba(0,0,0,.22)'; ctx.fillRect(0,0,W,H);

    for(const e of contactElems){
      if(e.type!=='line'){ e.x+=e.vx; e.y+=e.vy; if(e.x<-60) e.x=W+40; if(e.x>W+60) e.x=-40; if(e.y<-60) e.y=H+40; if(e.y>H+60) e.y=-40; }
      if(e.type==='line'){ e.x1+=e.vx1; e.y1+=e.vy1; e.x2+=e.vx2; e.y2+=e.vy2; ['x1','y1','x2','y2'].forEach(k=>{ if(e[k]<-80) e[k]=W+40; if(e[k]>W+80) e[k]=-40; }); }
      if(e.rot!==undefined) e.rot+=e.vrot;

      if(e.type==='emoji'){
        const pulse = 0.78 + 0.22*Math.sin(t*1.1+e.phase);
        ctx.save();
        ctx.globalAlpha = e.alpha * pulse;
        ctx.translate(e.x, e.y);
        ctx.rotate(e.rot);
        ctx.font = e.size + 'px serif';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText(e.emoji, 0, 0);
        ctx.restore();
      } else if(e.type==='dot'){
        const alpha=.48+.28*Math.sin(t*1.9+e.phase);
        ctx.save(); ctx.globalAlpha=alpha;
        ctx.beginPath(); ctx.arc(e.x,e.y,e.r,0,Math.PI*2);
        ctx.fillStyle=e.color; ctx.fill(); ctx.restore();
      } else if(e.type==='line'){
        ctx.save(); ctx.globalAlpha=e.alpha;
        ctx.strokeStyle='rgba(100,145,255,.5)'; ctx.lineWidth=.8;
        ctx.setLineDash([4,9]);
        ctx.beginPath(); ctx.moveTo(e.x1,e.y1); ctx.lineTo(e.x2,e.y2); ctx.stroke();
        ctx.setLineDash([]);
        ctx.restore();
      } else if(e.type==='ring'){
        const alpha=.13+.07*Math.sin(t*1.3+e.phase);
        ctx.save(); ctx.globalAlpha=alpha;
        for(let ring=0;ring<3;ring++){
          ctx.beginPath(); ctx.arc(e.x,e.y,e.r*(ring+1)*.72,0,Math.PI*2);
          ctx.strokeStyle='rgba(100,165,255,.55)'; ctx.lineWidth=.9; ctx.stroke();
        }
        ctx.restore();
      }
    }
    contactAnimId=requestAnimationFrame(drawContactBg);
  }
  function startContactBg(){
    if(contactAnimId) return;
    contactBg.classList.add('visible');
    contactAnimId=requestAnimationFrame(drawContactBg);
  }
  function stopContactBg(){
    if(contactAnimId){ cancelAnimationFrame(contactAnimId); contactAnimId=null; }
    contactBg.classList.remove('visible');
  }

  function triggerStagger(root){
    root.querySelectorAll(".stagger-wrap").forEach(w => {
      w.classList.remove("stagger-in");
      void w.offsetWidth; /* force reflow so the animation restarts */
      w.classList.add("stagger-in");
    });
  }

  function goToPage(name){
    const current = document.querySelector(".page.active");
    const next = pages[name];
    if (!next || next === current) return;

    navItems.forEach(b => b.classList.toggle("active", b.dataset.target === name));
    placeIndicator(document.querySelector(".nav-item.active"));

    current.classList.add("leaving");
    setTimeout(() => {
      current.classList.remove("active", "leaving");
      next.classList.add("active");
      window.scrollTo({ top: 0, behavior: "instant" in window ? "instant" : "auto" });
      next.querySelectorAll(".reveal").forEach(el => el.classList.add("in"));
      triggerStagger(next);
      initScrollFx();
      if(name==='about'){ startAboutBg(); stopContactBg(); }
      else if(name==='contact'){ startContactBg(); stopAboutBg(); }
      else { stopAboutBg(); stopContactBg(); }
    }, 280);
  }

  triggerStagger(document);

  navItems.forEach(btn => btn.addEventListener("click", () => goToPage(btn.dataset.target)));
  document.querySelectorAll('[data-action="go-contact"]').forEach(b => b.addEventListener("click", () => goToPage("contact")));
  document.querySelectorAll('[data-action="view-portfolio"]').forEach(b => b.addEventListener("click", () => {
    document.getElementById("services").scrollIntoView({ behavior: "smooth", block: "start" });
  }));

  /* ---------- scroll reveal + counters + skill bars + scroll progress ---------- */
  function animateCount(el){
    const target = parseInt(el.dataset.count, 10);
    const suffix = el.dataset.suffix || "";
    const dur = 1000;
    const start = performance.now();
    function tick(now){
      const p = Math.min(1, (now - start) / dur);
      el.textContent = Math.round(target * (1 - Math.pow(1 - p, 3))) + suffix;
      if (p < 1) requestAnimationFrame(tick);
    }
    requestAnimationFrame(tick);
  }

  let countersObserver, skillsObserver, tlObserver, revealObserver;

  function initScrollFx(){
    if (countersObserver) countersObserver.disconnect();
    if (skillsObserver) skillsObserver.disconnect();
    if (tlObserver) tlObserver.disconnect();
    if (revealObserver) revealObserver.disconnect();

    countersObserver = new IntersectionObserver((entries) => {
      entries.forEach(e => { if (e.isIntersecting){ animateCount(e.target); countersObserver.unobserve(e.target); } });
    }, { threshold: .5 });
    document.querySelectorAll(".page.active .stat-num[data-count]").forEach(el => countersObserver.observe(el));

    skillsObserver = new IntersectionObserver((entries) => {
      entries.forEach(e => {
        if (e.isIntersecting){
          const fill = e.target.dataset.fill;
          e.target.style.width = fill + "%";
          skillsObserver.unobserve(e.target);
        }
      });
    }, { threshold: .4 });
    document.querySelectorAll(".page.active .skill-fill").forEach(el => skillsObserver.observe(el));

    tlObserver = new IntersectionObserver((entries) => {
      entries.forEach(e => { if (e.isIntersecting) e.target.classList.add("seen"); });
    }, { threshold: .6 });
    document.querySelectorAll(".page.active .tl-card").forEach(el => tlObserver.observe(el));

    revealObserver = new IntersectionObserver((entries) => {
      entries.forEach(e => { if (e.isIntersecting) e.target.classList.add("in"); });
    }, { threshold: .15 });
    document.querySelectorAll(".page.active .reveal:not(.in)").forEach(el => revealObserver.observe(el));
  }
  initScrollFx();

  const progressEl = document.getElementById("progress");
  window.addEventListener("scroll", () => {
    const h = document.documentElement.scrollHeight - window.innerHeight;
    progressEl.style.width = (h > 0 ? (window.scrollY / h) * 100 : 0) + "%";
  });

  /* ---------- tilt on pointer for cards (desktop) / ripple on tap ---------- */
  if (window.matchMedia("(hover: hover)").matches){
    document.querySelectorAll(".tilt-card").forEach(card => {
      card.addEventListener("mousemove", (e) => {
        const r = card.getBoundingClientRect();
        const x = (e.clientX - r.left) / r.width - .5;
        const y = (e.clientY - r.top) / r.height - .5;
        card.style.transform = "perspective(600px) rotateX(" + (y * -6) + "deg) rotateY(" + (x * 6) + "deg) translateY(-2px)";
      });
      card.addEventListener("mouseleave", () => { card.style.transform = ""; });
    });
  }

  document.querySelectorAll(".btn").forEach(btn => {
    btn.addEventListener("click", (e) => {
      const r = btn.getBoundingClientRect();
      const ripple = document.createElement("span");
      ripple.className = "ripple";
      ripple.style.left = (e.clientX - r.left - 6) + "px";
      ripple.style.top = (e.clientY - r.top - 6) + "px";
      ripple.style.width = ripple.style.height = "12px";
      btn.appendChild(ripple);
      setTimeout(() => ripple.remove(), 650);
    });
  });

  /* ---------- contact form (front-end only, see note in UI) ---------- */
 document.getElementById("contactForm").addEventListener("submit", (e) => {
  e.preventDefault();

  const form = e.target;
  const btn = form.querySelector(".send-btn");

  if (btn.dataset.state !== "idle") return;
  btn.dataset.state = "sending";

  const name = document.getElementById("f-name").value;
  const email = document.getElementById("f-email").value;
  const project = document.getElementById("f-type").value;
  const message = document.getElementById("f-message").value;

  const phone = "917990127718";

  const text = `*New Portfolio Enquiry*%0A%0A
👤 Name: ${name}%0A
📧 Email: ${email}%0A
💼 Project Type: ${project}%0A%0A
📝 Message:%0A${message}`;

  setTimeout(() => {
    btn.dataset.state = "sent";

    window.open(
      `https://wa.me/${phone}?text=${text}`,
      "_blank"
    );

    setTimeout(() => {
      btn.dataset.state = "idle";
      form.reset();
    }, 2200);

  }, 800);
});

  /* ---------- particle canvas background ---------- */
  const canvas = document.getElementById("particles");
  const ctx = canvas.getContext("2d");
  const reduceMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  let particles = [];

  function sizeCanvas(){
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
  }
  function makeParticles(){
    const count = reduceMotion ? 0 : Math.min(36, Math.floor((canvas.width * canvas.height) / 26000));
    particles = Array.from({ length: count }, () => ({
      x: Math.random() * canvas.width,
      y: Math.random() * canvas.height,
      r: Math.random() * 1.6 + .4,
      vx: (Math.random() - .5) * .15,
      vy: (Math.random() - .5) * .15,
      a: Math.random() * .5 + .15
    }));
  }
  function drawParticles(){
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    particles.forEach(p => {
      p.x += p.vx; p.y += p.vy;
      if (p.x < 0) p.x = canvas.width; if (p.x > canvas.width) p.x = 0;
      if (p.y < 0) p.y = canvas.height; if (p.y > canvas.height) p.y = 0;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
      ctx.fillStyle = "rgba(160,200,255," + p.a + ")";
      ctx.fill();
    });
    if (!reduceMotion) requestAnimationFrame(drawParticles);
  }
  sizeCanvas(); makeParticles(); drawParticles();
  window.addEventListener("resize", () => { sizeCanvas(); makeParticles(); });

});
